Here's a complete example:

**XAML**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
        <CollectionView.EmptyView>
            <Label Text="No items found."
                   HorizontalOptions="Center" VerticalOptions="Center" />
        </CollectionView.EmptyView>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    public ItemsViewModel(IApiService api, INavigationService nav)
    {
        _api = api;
        _nav = nav;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false;   // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null;        // reset so the same row can be tapped again
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `IsRefreshing` (bool) | Must be set to `false` when load finishes or the spinner never stops |
| `Command` | `RefreshCommand` | Generated by `[RelayCommand]` from `RefreshAsync` |
| `ItemsSource` | `Items` | `ObservableCollection<T>` so the UI updates on add/remove |
| `SelectedItem` | `SelectedItem` | Two-way by default; null it after navigation so re-selection works |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires after `SelectedItem` updates, so the property is already set |

**Things to watch out for:**
- **Always set `IsRefreshing = false`** in a `finally` block — if the API throws, the spinner will hang otherwise.
- **Null `SelectedItem` after navigating** — CollectionView won't fire `SelectionChanged` again for an already-selected item.
- **`SelectionMode="Single"`** is required; the default is `None`, which disables selection entirely.
